function computePrice(bikeReduction, car, bike, i) {
  // if (addFreeBike[i] && car >= 4 && bike >= 2)
  //   return car * 300 + (bike - 2) * 100;
  if (!bikeReduction) return car * 300 + bike * 100;
  //else if (moneyReduction) return car * 300 + moto * 150 - 50;
  else return car * 300 + (bike - 1) * 100;
}

export function Original(car, moto, bike, operation, i) {
  var bikeNumber = bike;
  var rentalPrice = 0;

  if (operation === "cP") {
    if (car >= 3) {
      reduction[i] = true;
      if (bike === 0) {
        bikeNumber = 1;
        addFreeBike[i] = true;
        rentalPrice = computePrice(reduction[i], car, bikeNumber);
      } else rentalPrice = computePrice(reduction[i], car, bikeNumber);
    } else {
      rentalPrice = computePrice(reduction[i], car, bikeNumber);
    }
  } else if (operation === "cM") {
    if (car >= 3) rentalPrice = computePrice(reduction[i], car, bikeNumber);
    else {
      reduction[i] = false;
      if (addFreeBike[i]) {
        bikeNumber--;
        addFreeBike[i] = false;
      }
      rentalPrice = computePrice(reduction[i], car, bikeNumber);
    }
  } else if (operation === "bP") {
    if (car >= 3) {
      reduction[i] = true;
      rentalPrice = computePrice(reduction[i], car, bikeNumber);
    } else rentalPrice = computePrice(reduction[i], car, bikeNumber);
  } else if (operation === "bM")
    if (car >= 3) {
      if (bike > 0) rentalPrice = computePrice(reduction[i], car, bikeNumber);
      else {
        reduction[i] = false;
        addFreeBike[i] = false;
        rentalPrice = computePrice(reduction[i], car, bikeNumber);
      }
    } else rentalPrice = computePrice(reduction[i], car, bikeNumber);

  return { bikeNumber, rentalPrice };
}

