import React, { useState } from "react";

import "./App.css";
import { array_of_mutants, Original, init } from "./mutants-book";

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function Rental() {
  var [eredmeny, setEredmeny] = useState("-");
  var [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  var [killed] = useState([]);
  //var [wrongTests, setWrongTests] = useState('')
  var [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  var [mutant] = useState([]);
  var [wrongSolution, setWrongSolution] = useState(false);
  var [carNumber, setCarNumber] = useState("0");
  var [motoNumber, setMotoNumber] = useState("0");
  var [bikeNumber, setBikeNumber] = useState("0");

  for (var i = 0; i < array_of_mutants.length; i++) {
    if (killed[i] === undefined) {
      killed[i] = false;
    }
  }

  if (wrongTests[0] === undefined) wrongTests[0] = "";

  function nextTest() {
    setBikeNumber(0);
    setCarNumber(0);
    setMotoNumber(0);
    setEredmeny(0);
    init();
  }

  async function downloadTasks() {
    document.getElementById("downloader").click();
  }

  function tryAgain() {
    // window.location.href = '/'
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
    }
    nextTest();
    setNumber(0);
    setPrintWrongTests("");
    setResult("");
    setMissing("");
  }

  function callFunctions(operation) {
    var car = +carNumber;
    var moto = +motoNumber;
    var bike = +bikeNumber;
    //var mutantVacationDays = 0
    var killedMutants1 = "";

    var result = Original(car, moto, bike, operation, 0);
    var totalPrice = result.rentalPrice;
    bikeNumber = result.bikeNumber;
    setBikeNumber(bikeNumber);

    setEredmeny(totalPrice); //!!!!!!!!!!!!! go to here!
    var superfluousTest = true;
    var mutantResult = { bikeNumber: 0, rentalPrice: 0, mutant: "" };
    testCaseNumber++;
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        mutantResult = array_of_mutants[i](car, moto, bike, operation, i + 1);
        mutant[i] = mutantResult.mutant;

        if (
          +totalPrice !== +mutantResult.rentalPrice ||
          +bikeNumber !== +mutantResult.bikeNumber
        ) {
          var j = i + 1;
          killedMutants1 = killedMutants1 + j + " ";
          killed[i] = true;
          mutant[i] = "";
          superfluousTest = false;
          console.log("killed mutant: ", i + 1);
        }
      }
    }

    setKilledMutants(killedMutants1);
    setNumber(testCaseNumber);
  }

  function printResult() {
    var missingTests = false;
    var missedTestNumber = 0;

    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "The following you should do: " + mutant[i]; //'Some necessary test cases are missing.'
        missingTests = true;
        missedTestNumber++;
        //   console.log('not killed ', i)
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);

    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
      alert("Please write your test cases!");
      return;
    } else if (
      !missingTests //&&
      //   !wrongSolution &&
      //   testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design!";
      missing = "---";
      setMissing(missing);
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        {console.log("---------------------------")}
        <p class="exercise">
          {" "}
          Read the specification below carefully. Add the test cases one by one.
          A test case ends with 'Next test'. You can continue adding test cases
          after 'Show my result'. <br />
          'Try again' starts a new test design session. &nbsp;&nbsp;You can use
          &nbsp;
          <a href="https://cloud.harmony.ac/">Harmony</a> to make action-state
          test design and execute tests automatedly.
        </p>

        <p class="specification">
          {" "}
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Car Rental </b>
          </div>
          A rental company loans cars (EUR 300), and bikes (EUR 100) for a week.{" "}
          <br />
          <b>R1</b> The customer can add cars or bikes one by one to the rental
          order.
          <br />
          <b>R2</b> The customer can remove cars or bikes one by one from the
          rental order. <br />
          <b>R3</b> If the customer rents cars for more than EUR 600, then they
          can rent one bike for free. In case of discount: <br />
          <b>&nbsp;&nbsp;&nbsp;&nbsp; R3a</b> If the customer has selected some
          bikes previously, then one of them becomes free. <br />
          <b>&nbsp;&nbsp;&nbsp;&nbsp; R3b</b> If the customer hasn't selected a
          bike previously, then one free bike is added. <br />
          <b>R4</b> If the customer deletes some cars or motorcycles from the
          order that the offering threshold doesn't hold, then any offering will
          be withdrawn.
          <br />
          <b>&nbsp;&nbsp;&nbsp;&nbsp; R4a</b> When the discount is withdrawn but
          given again, and no bike was added meanwhile, the customer gets the
          previous discount back.
          <br />
          <b>&nbsp;&nbsp;&nbsp;&nbsp; R4b</b> When an offering is withdrawn but
          given again, and no bike was added/deleted meanwhile, the customer
          gets the previous offering back.
          <br />
          <b>R5</b> If the customer deletes the free bike, then no money
          discount is given. Adding the bike back the discount is given again by
          converting the bike price to zero. &nbsp;&nbsp;{" "}
        </p>

        <p class="testcases">
          <div>
            {missing.length > 0 ? (
              <span data-harmony-id="Missing test">
                {" "}
                {missing} <br />
              </span>
            ) : (
              <span data-harmony-id="Wrong test">
                {" "}
                {wrongTests[0]} <br />
              </span>
            )}
          </div>
          <span data-harmony-id="result">{result}</span> <br />
          <br />
          Cars:{" "}
          <span
            data-harmony-id="Car number"
            style={{ color: "mediumaquamarine" }}
          >
            {carNumber}
          </span>{" "}
          <button
            class="button"
            data-harmony-id="Car + button"
            onClick={() => {
              carNumber++;
              setCarNumber(carNumber);
              callFunctions("cP");
            }}
          >
            <b>+</b>
          </button>
          <button
            class="button"
            data-harmony-id="Car - button"
            onClick={() => {
              if (carNumber > 0) {
                carNumber--;
                setCarNumber(carNumber);

                callFunctions("cM");
              }
            }}
          >
            <b>-</b>
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;Bikes:{" "}
          <span
            data-harmony-id="Bike number"
            style={{ color: "mediumaquamarine" }}
          >
            {bikeNumber}
          </span>{" "}
          <button
            class="button"
            //  data-harmony-id='Bike + button'
            data-harmony-id="Bike + button"
            onClick={() => {
              bikeNumber++;

              setBikeNumber(bikeNumber);
              callFunctions("bP");
            }}
          >
            <b>+</b>
          </button>
          <button
            class="button"
            data-harmony-id="Bike - button"
            onClick={() => {
              if (bikeNumber > 0) {
                bikeNumber--;
                setBikeNumber(bikeNumber);
                callFunctions("bM");
              }
            }}
          >
            <b>-</b>
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp; Total rental price:{" "}
          <span data-harmony-id="Rental price">{eredmeny}</span>
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <span
            data-harmony-id="Test case number"
            style={{ color: "mediumaquamarine" }}
          >
            Number of test steps: {testCaseNumber}
          </span>{" "}
          <br /> <br />
          <button class="button" data-harmony-id="Next test" onClick={nextTest}>
            {" "}
            Next test{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Stop" onClick={printResult}>
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={tryAgain}>
            {" "}
            Try again{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          {/*}
          <button
            class="download"
            data-harmony-id="Download"
            onClick={downloadTasks}
          >
            {" "}
            Download templates{" "}
          </button>{" "}
          <a
            id="downloader"
            href="../templates/car_rental_templates.zip"
            download
            hidden
          ></a>
          <br />
          */}
          {/*killedMutant: <span>{killedMutants}</span> <br/> */}
        </p>
      </header>
    </div>
  );
}

export default Rental;
